    public static void main(String[] args) {
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // ===================================================================
        // CRITICAL CONFIGURATION: PRESERVE FORMATTING (SNIPER MODE)
        // ===================================================================
        // 1. Enable comments to prevent stripping
        launcher.getEnvironment().setCommentEnabled(true);

        // 2. Force SniperJavaPrettyPrinter. 
        // This instructs Spoon to only print changes to the AST, preserving
        // original white-space and formatting for untouched code.
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );

        // ===================================================================
        // DEFENSIVE CONFIGURATION: NO CLASSPATH
        // ===================================================================
        // Allows running without full dependency resolution.
        // Processors must handle unknown/null types gracefully.
        launcher.getEnvironment().setNoClasspath(true);

        launcher.addProcessor(new TemplateProcessor());

        try {
            launcher.run();
            System.out.println("Migration finished. Output in: " + outputPath);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
